import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

const PostReview = () => {
    const navigate = useNavigate();
    const { id } = useParams();
    const [review, setReview] = useState("");

    // useEffect with empty array to avoid dependency warnings
    useEffect(() => {
        console.log("Reviewing dealer ID:", id);
    }, [id]);

    const handlePostReview = () => {
        console.log("Review submitted:", review);
        // Add your submission logic here
    };

    return (
        <div style={{ padding: '40px', maxWidth: '600px' }}>
            <h2 style={{ color: '#6a1b9a' }}>Post a Review</h2>
            <hr />
            <div style={{ marginTop: '20px' }}>
                <label>Write your review for Dealer {id}:</label>
                <textarea 
                    style={{ width: '100%', height: '150px', marginTop: '10px', display: 'block' }}
                    value={review}
                    onChange={(e) => setReview(e.target.value)}
                />
            </div>
            <button 
                onClick={handlePostReview}
                style={{ backgroundColor: '#6a1b9a', color: 'white', padding: '10px 20px', border: 'none', marginTop: '20px', cursor: 'pointer' }}
            >
                Submit Review
            </button>
            <button 
                onClick={() => navigate(-1)} 
                style={{ marginLeft: '10px', padding: '10px 20px' }}
            >
                Cancel
            </button>
        </div>
    );
};

export default PostReview;
